cell("code","class Matrix:\n    def __init__(self, data):\n        # data is a 2D list, e.g. [[1, 2], [3, 4]]\n        # Create a deep copy to prevent mutation bugs!\n        self.data = [list(row) for row in data]\n        self.num_rows = len(self.data)\n        self.num_cols = len(self.data[0]) if self.num_rows > 0 else 0\n\n    def add(self, other):\n        if self.num_rows != other.num_rows or self.num_cols != other.num_cols:\n            raise ValueError(\"Dimensions do not match for addition.\")\n        # Create new 2D list for result\n        # YOUR CODE HERE\n        pass\n\n    # Implement subtract, scalar_multiply, and transpose\n    # YOUR CODE HERE\n    pass\n\n# Test logic\n# m1 = Matrix([[1, 2], [3, 4]])\n# m2 = Matrix([[5, 6], [7, 8]])\n# print(\"Addition:\", m1.add(m2).data) # Should be [[6, 8], [10, 12]]"),
